import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as r,d as t}from"./app-0a44add1.js";const n={},i=t(`<h2 id="webglrenderer" tabindex="-1"><a class="header-anchor" href="#webglrenderer" aria-hidden="true">#</a> WebGLRenderer</h2><h2 id="构造器" tabindex="-1"><a class="header-anchor" href="#构造器" aria-hidden="true">#</a> 构造器</h2><h3 id="webglrenderer-parameters-object" tabindex="-1"><a class="header-anchor" href="#webglrenderer-parameters-object" aria-hidden="true">#</a> WebGLRenderer( parameters : Object )</h3><p>parameters - (可选) 该对象的属性定义了渲染器的行为。也可以完全不传参数。在所有情况下，当缺少参数时，它将采用合理的默认值。 以下是合法参数：</p><ul><li>canvas - 一个供渲染器绘制其输出的canvas 它和下面的domElement属性对应。 如果没有传这个参数，会创建一个新canvas</li><li>context - 可用于将渲染器附加到已有的渲染环境(RenderingContext)中。默认值是null</li><li>precision - 着色器精度. 可以是 &quot;highp&quot;, &quot;mediump&quot; 或者 &quot;lowp&quot;. 如果设备支持，默认为&quot;highp&quot;</li><li>alpha - 控制默认的清除alpha值。当设置为true时，值为0。否则就是1。默认为false</li><li>premultipliedAlpha - renderer是否假设颜色有 premultiplied alpha. 默认为true</li><li>antialias - 是否执行抗锯齿。默认为false.</li><li>stencil - 绘图缓存是否有一个至少8位的模板缓存(stencil buffer)。默认为true</li><li>preserveDrawingBuffer -是否保留缓直到手动清除或被覆盖。 默认false.</li><li>powerPreference - 提示用户代理怎样的配置更适用于当前WebGL环境。 可能是&quot;high-performance&quot;, &quot;low-power&quot; 或 &quot;default&quot;。默认是&quot;default&quot;. 详见WebGL spec</li><li>failIfMajorPerformanceCaveat - 检测渲染器是否会因性能过差而创建失败。默认为false。详见 WebGL spec for details.</li><li>depth - 绘图缓存是否有一个至少6位的深度缓存(depth buffer )。 默认是true.</li><li>logarithmicDepthBuffer - 是否使用对数深度缓存。如果要在单个场景中处理巨大的比例差异，就有必要使用。</li></ul><h2 id="属性" tabindex="-1"><a class="header-anchor" href="#属性" aria-hidden="true">#</a> 属性</h2><h3 id="autoclear-boolean" tabindex="-1"><a class="header-anchor" href="#autoclear-boolean" aria-hidden="true">#</a> .autoClear : Boolean</h3><p>定义渲染器是否在渲染每一帧之前自动清除其输出。</p><h3 id="autoclearcolor-boolean" tabindex="-1"><a class="header-anchor" href="#autoclearcolor-boolean" aria-hidden="true">#</a> .autoClearColor : Boolean</h3><p>如果autoClear为true, 定义renderer是否清除颜色缓存。 默认是true</p><h3 id="autocleardepth-boolean" tabindex="-1"><a class="header-anchor" href="#autocleardepth-boolean" aria-hidden="true">#</a> .autoClearDepth : Boolean</h3><p>如果autoClear是true, 定义renderer是否清除深度缓存。 默认是true</p><h3 id="autoclearstencil-boolean" tabindex="-1"><a class="header-anchor" href="#autoclearstencil-boolean" aria-hidden="true">#</a> .autoClearStencil : Boolean</h3><p>如果autoClear是true, 定义renderer是否清除模板缓存. 默认是true</p><h3 id="debug-object" tabindex="-1"><a class="header-anchor" href="#debug-object" aria-hidden="true">#</a> .debug : Object</h3><ul><li>checkShaderErrors: 如果为true，定义是否检查材质着色器程序 编译和链接过程中的错误。 禁用此检查生产以获得性能增益可能很有用。 强烈建议在开发期间保持启用这些检查。 如果着色器没有编译和链接 - 它将无法工作，并且相关材料将不会呈现。 默认是true</li></ul><h3 id="capabilities-object" tabindex="-1"><a class="header-anchor" href="#capabilities-object" aria-hidden="true">#</a> .capabilities : Object</h3><p>一个包含当前渲染环境(RenderingContext)的功能细节的对象。</p><ul><li>floatFragmentTextures: 环境是否支持OES_texture_float扩展</li><li>floatVertexTextures: 如果floatFragmentTextures和vertexTextures都是true， 则此值为true</li><li>getMaxAnisotropy(): 返回最大可用各向异性。</li><li>getMaxPrecision(): 返回顶点着色器和片元着色器的最大可用精度。</li><li>isWebGL2: true if the context in use is a WebGL2RenderingContext object.</li><li>logarithmicDepthBuffer: 如果logarithmicDepthBuffer在构造器中被设为true且 环境支持EXT_frag_depth扩展，则此值为true</li><li>maxAttributes: gl.MAX_VERTEX_ATTRIBS的值</li><li>maxCubemapSize: gl.MAX_CUBE_MAP_TEXTURE_SIZE 的值，着色器可使用的立方体贴图纹理的最大宽度*高度</li><li>maxFragmentUniforms: gl.MAX_FRAGMENT_UNIFORM_VECTORS的值，片元着色器可使用的全局变量(uniforms)数量</li><li>maxSamples: The value of gl.MAX_SAMPLES. Maximum number of samples in context of Multisample anti-aliasing (MSAA).</li><li>maxTextureSize: gl.MAX_TEXTURE_SIZE的值，着色器可使用纹理的最大宽度*高度</li><li>maxTextures: *gl.MAX_TEXTURE_IMAGE_UNITS的值，着色器可使用的纹理数量</li><li>maxVaryings: gl.MAX_VARYING_VECTORS的值，着色器可使用矢量的数量</li><li>maxVertexTextures: gl.MAX_VERTEX_TEXTURE_IMAGE_UNITS的值，顶点着色器可使用的纹理数量。</li><li>maxVertexUniforms: gl.MAX_VERTEX_UNIFORM_VECTORS的值，顶点着色器可使用的全局变量(uniforms)数量</li><li>precision: 渲染器当前使用的着色器的精度</li><li>vertexTextures: 如果 .maxVertexTextures : Integer大于0，此值为true (即可以使用顶点纹理)</li></ul><h3 id="clippingplanes-array" tabindex="-1"><a class="header-anchor" href="#clippingplanes-array" aria-hidden="true">#</a> .clippingPlanes : Array</h3><p>用户自定义的剪裁平面，在世界空间中被指定为THREE.Plane对象。 这些平面全局使用。空间中与该平面点积为负的点将被切掉。 默认值是[]</p><h3 id="domelement-domelement" tabindex="-1"><a class="header-anchor" href="#domelement-domelement" aria-hidden="true">#</a> .domElement : DOMElement</h3><p>一个canvas，渲染器在其上绘制输出。<br> 渲染器的构造函数会自动创建(如果没有传入canvas参数);你需要做的仅仅是像下面这样将它加页面里去:</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>document<span class="token punctuation">.</span>body<span class="token punctuation">.</span><span class="token function">appendChild</span><span class="token punctuation">(</span> renderer<span class="token punctuation">.</span>domElement <span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="extensions-object" tabindex="-1"><a class="header-anchor" href="#extensions-object" aria-hidden="true">#</a> .extensions : Object</h3><ul><li>get( extensionName : String ): 用于检查是否支持各种扩展，并返回一个对象，其中包含扩展的详细信息。 该方法检查以下扩展： <ul><li>WEBGL_depth_texture</li><li>EXT_texture_filter_anisotropic</li><li>WEBGL_compressed_texture_s3tc</li><li>WEBGL_compressed_texture_pvrtc</li><li>WEBGL_compressed_texture_etc1</li></ul></li></ul><h3 id="outputencoding-number" tabindex="-1"><a class="header-anchor" href="#outputencoding-number" aria-hidden="true">#</a> .outputEncoding : number</h3><p>定义渲染器的输出编码。默认为THREE.LinearEncoding</p><p>如果渲染目标已经使用 .setRenderTarget、之后将直接使用renderTarget.texture.encoding</p><p>查看texture constants页面以获取其他格式细节</p><h3 id="info-object" tabindex="-1"><a class="header-anchor" href="#info-object" aria-hidden="true">#</a> .info : Object</h3><p>一个对象，包含有关图形板内存和渲染过程的一系列统计信息。这些信息可用于调试或仅仅满足下好奇心。该对象包含以下字段:</p><ul><li>memory: <ul><li>geometries</li><li>textures</li></ul></li><li>render: <ul><li>calls</li><li>triangles</li><li>points</li><li>lines</li><li>frame</li></ul></li><li>programs</li></ul><p>默认情况下，这些字段在每次渲染调用时都会重置，但是当每帧有多个渲染通道时（例如，使用后处理时），最好使用自定义模式重置。先将 autoReset 设置为 false.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>renderer<span class="token punctuation">.</span>info<span class="token punctuation">.</span>autoReset <span class="token operator">=</span> <span class="token boolean">false</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>然后在单个帧时渲染完成后调用 reset().</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>renderer<span class="token punctuation">.</span>info<span class="token punctuation">.</span><span class="token function">reset</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="localclippingenabled-boolean" tabindex="-1"><a class="header-anchor" href="#localclippingenabled-boolean" aria-hidden="true">#</a> .localClippingEnabled : Boolean</h3><p>定义渲染器是否考虑对象级剪切平面。 默认为false.</p><h3 id="physicallycorrectlights-boolean" tabindex="-1"><a class="header-anchor" href="#physicallycorrectlights-boolean" aria-hidden="true">#</a> .physicallyCorrectLights : Boolean</h3><p>是否使用物理上正确的光照模式。 默认是false。 示例：lights / physical</p><h3 id="properties-object" tabindex="-1"><a class="header-anchor" href="#properties-object" aria-hidden="true">#</a> .properties : Object</h3><p>渲染器内部使用，以跟踪各种子对象属性。</p><h3 id="renderlists-webglrenderlists" tabindex="-1"><a class="header-anchor" href="#renderlists-webglrenderlists" aria-hidden="true">#</a> .renderLists : WebGLRenderLists</h3><p>在内部用于处理场景渲染对象的排序。</p><h3 id="shadowmap-webglshadowmap" tabindex="-1"><a class="header-anchor" href="#shadowmap-webglshadowmap" aria-hidden="true">#</a> .shadowMap : WebGLShadowMap</h3><p>如果使用，它包含阴影贴图的引用。</p><ul><li><p>enabled: 如果设置开启，允许在场景中使用阴影贴图。默认是 false。</p></li><li><p>autoUpdate: 启用场景中的阴影自动更新。默认是true<br> 如果不需要动态光照/阴影, 则可以在实例化渲染器时将之设为false</p></li><li><p>needsUpdate: 当被设为true, 场景中的阴影贴图会在下次render调用时刷新。默认是false<br> 如果你已经禁用了阴影贴图的自动更新(shadowMap.autoUpdate = false), 那么想要在下一次渲染时更新阴影的话就需要将此值设为true</p></li><li><p>type: 定义阴影贴图类型 (未过滤, 关闭部分过滤, 关闭部分双线性过滤), 可选值有:</p><ul><li>THREE.BasicShadowMap</li><li>THREE.PCFShadowMap (默认)</li><li>THREE.PCFSoftShadowMap</li><li>THREE.VSMShadowMap</li></ul></li></ul><p>详见Renderer constants</p><h3 id="sortobjects-boolean" tabindex="-1"><a class="header-anchor" href="#sortobjects-boolean" aria-hidden="true">#</a> .sortObjects : Boolean</h3><p>定义渲染器是否应对对象进行排序。默认是true.</p><p>说明: 排序用于尝试正确渲染出具有一定透明度的对象。根据定义，排序可能不总是有用。根据应用的需求，可能需要关闭排序并使其他方法来处理透明度的渲染，例如， 手动确定每个对象的渲染顺序。</p><h3 id="state-object" tabindex="-1"><a class="header-anchor" href="#state-object" aria-hidden="true">#</a> .state : Object</h3><p>包含设置WebGLRenderer.context状态的各种属性的函数。</p><h3 id="tonemapping-constant" tabindex="-1"><a class="header-anchor" href="#tonemapping-constant" aria-hidden="true">#</a> .toneMapping : Constant</h3><p>默认是NoToneMapping。查看Renderer constants以获取其它备选项</p><h3 id="tonemappingexposure-number" tabindex="-1"><a class="header-anchor" href="#tonemappingexposure-number" aria-hidden="true">#</a> .toneMappingExposure : Number</h3><p>色调映射的曝光级别。默认是1</p><h3 id="xr-webxrmanager" tabindex="-1"><a class="header-anchor" href="#xr-webxrmanager" aria-hidden="true">#</a> .xr : WebXRManager</h3><p>提供对呈现器的WebXR相关接口的访问</p><h2 id="方法" tabindex="-1"><a class="header-anchor" href="#方法" aria-hidden="true">#</a> 方法</h2><h3 id="clear-color-boolean-depth-boolean-stencil-boolean-undefined" tabindex="-1"><a class="header-anchor" href="#clear-color-boolean-depth-boolean-stencil-boolean-undefined" aria-hidden="true">#</a> .clear ( color : Boolean, depth : Boolean, stencil : Boolean ) : undefined</h3><p>告诉渲染器清除颜色、深度或模板缓存. 此方法将颜色缓存初始化为当前颜色。参数们默认都是true</p><h3 id="clearcolor-undefined" tabindex="-1"><a class="header-anchor" href="#clearcolor-undefined" aria-hidden="true">#</a> .clearColor ( ) : undefined</h3><p>清除颜色缓存。 相当于调用.clear( true, false, false )</p><h3 id="cleardepth-undefined" tabindex="-1"><a class="header-anchor" href="#cleardepth-undefined" aria-hidden="true">#</a> .clearDepth ( ) : undefined</h3><p>清除深度缓存。相当于调用.clear( false, true, false )</p><h3 id="clearstencil-undefined" tabindex="-1"><a class="header-anchor" href="#clearstencil-undefined" aria-hidden="true">#</a> .clearStencil ( ) : undefined</h3><p>清除模板缓存。相当于调用.clear( false, false, true )</p><h3 id="compile-scene-object3d-camera-camera-undefined" tabindex="-1"><a class="header-anchor" href="#compile-scene-object3d-camera-camera-undefined" aria-hidden="true">#</a> .compile ( scene : Object3D, camera : Camera ) : undefined</h3><p>使用相机编译场景中的所有材质。这对于在首次渲染之前预编译着色器很有用。</p><h3 id="copyframebuffertotexture-position-vector2-texture-framebuffertexture-level-number-undefined" tabindex="-1"><a class="header-anchor" href="#copyframebuffertotexture-position-vector2-texture-framebuffertexture-level-number-undefined" aria-hidden="true">#</a> .copyFramebufferToTexture ( position : Vector2, texture : FramebufferTexture, level : Number ) : undefined</h3><p>将当前WebGLFramebuffer中的像素复制到2D纹理中。可访问WebGLRenderingContext.copyTexImage2D.</p><h3 id="copytexturetotexture-position-vector2-srctexture-texture-dsttexture-texture-level-number-undefined" tabindex="-1"><a class="header-anchor" href="#copytexturetotexture-position-vector2-srctexture-texture-dsttexture-texture-level-number-undefined" aria-hidden="true">#</a> .copyTextureToTexture ( position : Vector2, srcTexture : Texture, dstTexture : Texture, level : Number ) : undefined</h3><p>将纹理的所有像素复制到一个已有的从给定位置开始的纹理中。可访问WebGLRenderingContext.texSubImage2D.</p><h3 id="dispose-undefined" tabindex="-1"><a class="header-anchor" href="#dispose-undefined" aria-hidden="true">#</a> .dispose ( ) : undefined</h3><p>处理当前的渲染环境</p><h3 id="forcecontextloss-undefined" tabindex="-1"><a class="header-anchor" href="#forcecontextloss-undefined" aria-hidden="true">#</a> .forceContextLoss () : undefined</h3><p>模拟WebGL环境的丢失。需要支持 WEBGL_lose_context 扩展才能用。</p><h3 id="forcecontextrestore-undefined" tabindex="-1"><a class="header-anchor" href="#forcecontextrestore-undefined" aria-hidden="true">#</a> .forceContextRestore ( ) : undefined</h3><p>模拟WebGL环境的恢复。需要支持 WEBGL_lose_context 扩展才能用。</p><h3 id="getclearalpha-float" tabindex="-1"><a class="header-anchor" href="#getclearalpha-float" aria-hidden="true">#</a> .getClearAlpha () : Float</h3><p>返回一个表示当前alpha值的float，范围0到1</p><h3 id="getclearcolor-target-color-color" tabindex="-1"><a class="header-anchor" href="#getclearcolor-target-color-color" aria-hidden="true">#</a> .getClearColor ( target : Color ) : Color</h3><p>返回一个表示当前颜色值的THREE.Color实例</p><h3 id="getcontext-webgl2renderingcontext" tabindex="-1"><a class="header-anchor" href="#getcontext-webgl2renderingcontext" aria-hidden="true">#</a> .getContext () : WebGL2RenderingContext</h3><p>返回当前WebGL环境</p><h3 id="getcontextattributes-webglcontextattributes" tabindex="-1"><a class="header-anchor" href="#getcontextattributes-webglcontextattributes" aria-hidden="true">#</a> .getContextAttributes () : WebGLContextAttributes</h3><p>返回一个对象，这个对象中存有在WebGL环境在创建的时候所设置的属性</p><h3 id="getactivecubeface-integer" tabindex="-1"><a class="header-anchor" href="#getactivecubeface-integer" aria-hidden="true">#</a> .getActiveCubeFace () : Integer</h3><p>Returns the current active cube face.</p><h3 id="getactivemipmaplevel-integer" tabindex="-1"><a class="header-anchor" href="#getactivemipmaplevel-integer" aria-hidden="true">#</a> .getActiveMipmapLevel () : Integer</h3><p>Returns the current active mipmap level.</p><h3 id="getrendertarget-rendertarget" tabindex="-1"><a class="header-anchor" href="#getrendertarget-rendertarget" aria-hidden="true">#</a> .getRenderTarget () : RenderTarget</h3><p>如果当前存在RenderTarget，则返回该值；否则返回null。</p><h3 id="getcurrentviewport-rendertarget" tabindex="-1"><a class="header-anchor" href="#getcurrentviewport-rendertarget" aria-hidden="true">#</a> .getCurrentViewport () : RenderTarget</h3><p>返回当前视口</p><h3 id="getdrawingbuffersize-object" tabindex="-1"><a class="header-anchor" href="#getdrawingbuffersize-object" aria-hidden="true">#</a> .getDrawingBufferSize () : Object</h3><p>返回一个包含渲染器绘图缓存宽度和高度(单位像素)的对象。</p><h3 id="getpixelratio-number" tabindex="-1"><a class="header-anchor" href="#getpixelratio-number" aria-hidden="true">#</a> .getPixelRatio () : number</h3><p>返回当前使用设备像素比</p><h3 id="getsize-target-vector2-vector2" tabindex="-1"><a class="header-anchor" href="#getsize-target-vector2-vector2" aria-hidden="true">#</a> .getSize ( target : Vector2 ) : Vector2</h3><p>返回包含渲染器输出canvas的宽度和高度(单位像素)的对象。</p><h3 id="inittexture-texture-texture-undefined" tabindex="-1"><a class="header-anchor" href="#inittexture-texture-texture-undefined" aria-hidden="true">#</a> .initTexture ( texture : Texture ) : undefined</h3><p>初始化给定的纹理。用于预加载纹理而不是等到第一次渲染（可能会由于解码和 GPU 上传的开销而导致明显的延迟）.</p><h3 id="resetglstate-undefined" tabindex="-1"><a class="header-anchor" href="#resetglstate-undefined" aria-hidden="true">#</a> .resetGLState ( ) : undefined</h3><p>将GL状态重置为默认值。WebGL环境丢失时会内部调用</p><h3 id="readrendertargetpixels-rendertarget-webglrendertarget-x-float-y-float-width-float-height-float-buffer-typedarray-activecubefaceindex-integer-undefined" tabindex="-1"><a class="header-anchor" href="#readrendertargetpixels-rendertarget-webglrendertarget-x-float-y-float-width-float-height-float-buffer-typedarray-activecubefaceindex-integer-undefined" aria-hidden="true">#</a> .readRenderTargetPixels ( renderTarget : WebGLRenderTarget, x : Float, y : Float, width : Float, height : Float, buffer : TypedArray, activeCubeFaceIndex : Integer ) : undefined</h3><p>buffer - Uint8Array is the only destination type supported in all cases, other types are renderTarget and platform dependent. See WebGL spec for details.</p><p>将renderTarget中的像素数据读取到传入的缓冲区中。这是WebGLRenderingContext.readPixels()的包装器<br> 示例：interactive / cubes / gpu</p><p>For reading out a WebGLCubeRenderTarget use the optional parameter activeCubeFaceIndex to determine which face should be read.</p><h3 id="render-scene-object3d-camera-camera-undefined" tabindex="-1"><a class="header-anchor" href="#render-scene-object3d-camera-camera-undefined" aria-hidden="true">#</a> .render ( scene : Object3D, camera : Camera ) : undefined</h3><p>用相机(camera)渲染一个场景(scene)或是其它类型的object。<br> 渲染一般是在canvas上完成的，或者是renderTarget(如果有指定)<br> 如果forceClear值是true，那么颜色、深度及模板缓存将会在渲染之前清除，即使渲染器的autoClear属性值是false<br> 即便forceClear设为true, 也可以通过将autoClearColor、autoClearStencil或autoClearDepth属性的值设为false来阻止对应缓存被清除。</p><h3 id="resetstate-undefined" tabindex="-1"><a class="header-anchor" href="#resetstate-undefined" aria-hidden="true">#</a> .resetState () : undefined</h3><p>可用于重置内部 WebGL 状态。此方法主要与跨多个 WebGL 库共享单个 WebGL 上下文的应用程序相关。</p><h3 id="setanimationloop-callback-function-undefined" tabindex="-1"><a class="header-anchor" href="#setanimationloop-callback-function-undefined" aria-hidden="true">#</a> .setAnimationLoop ( callback : Function ) : undefined</h3><p>callback — 每个可用帧都会调用的函数。 如果传入‘null’,所有正在进行的动画都会停止。</p><p>可用来代替requestAnimationFrame的内置函数. 对于WebXR项目，必须使用此函数。</p><h3 id="setclearalpha-alpha-float-undefined" tabindex="-1"><a class="header-anchor" href="#setclearalpha-alpha-float-undefined" aria-hidden="true">#</a> .setClearAlpha ( alpha : Float ) : undefined</h3><p>设置alpha。合法参数是一个0.0到 1.0之间的浮点数</p><h3 id="setclearcolor-color-color-alpha-float-undefined" tabindex="-1"><a class="header-anchor" href="#setclearcolor-color-color-alpha-float-undefined" aria-hidden="true">#</a> .setClearColor ( color : Color, alpha : Float ) : undefined</h3><p>设置颜色及其透明度</p><h3 id="setpixelratio-value-number-undefined" tabindex="-1"><a class="header-anchor" href="#setpixelratio-value-number-undefined" aria-hidden="true">#</a> .setPixelRatio ( value : number ) : undefined</h3><p>设置设备像素比。通常用于避免HiDPI设备上绘图模糊</p><h3 id="setrendertarget-rendertarget-webglrendertarget-activecubeface-integer-activemipmaplevel-integer-undefined" tabindex="-1"><a class="header-anchor" href="#setrendertarget-rendertarget-webglrendertarget-activecubeface-integer-activemipmaplevel-integer-undefined" aria-hidden="true">#</a> .setRenderTarget ( renderTarget : WebGLRenderTarget, activeCubeFace : Integer, activeMipmapLevel : Integer ) : undefined</h3><p>renderTarget -- 需要被激活的renderTarget(可选)。若此参数为空，则将canvas设置成活跃render target。<br> activeCubeFace -- Specifies the active cube side (PX 0, NX 1, PY 2, NY 3, PZ 4, NZ 5) of WebGLCubeRenderTarget. When passing a WebGLArrayRenderTarget or WebGL3DRenderTarget this indicates the z layer to render in to (optional).<br> activeMipmapLevel -- Specifies the active mipmap level (optional).</p><p>该方法设置活跃rendertarget。</p><h3 id="setscissor-x-integer-y-integer-width-integer-height-integer-undefined" tabindex="-1"><a class="header-anchor" href="#setscissor-x-integer-y-integer-width-integer-height-integer-undefined" aria-hidden="true">#</a> .setScissor ( x : Integer, y : Integer, width : Integer, height : Integer ) : undefined</h3><p>将剪裁区域设为(x, y)到(x + width, y + height) Sets the scissor area from</p><h3 id="setscissortest-boolean-boolean-undefined" tabindex="-1"><a class="header-anchor" href="#setscissortest-boolean-boolean-undefined" aria-hidden="true">#</a> .setScissorTest ( boolean : Boolean ) : undefined</h3><p>启用或禁用剪裁检测. 若启用，则只有在所定义的裁剪区域内的像素才会受之后的渲染器影响。</p><h3 id="setsize-width-integer-height-integer-updatestyle-boolean-undefined" tabindex="-1"><a class="header-anchor" href="#setsize-width-integer-height-integer-updatestyle-boolean-undefined" aria-hidden="true">#</a> .setSize ( width : Integer, height : Integer, updateStyle : Boolean ) : undefined</h3><p>将输出canvas的大小调整为(width, height)并考虑设备像素比，且将视口从(0, 0)开始调整到适合大小 将updateStyle设置为false以阻止对canvas的样式做任何改变。</p><h3 id="setviewport-x-integer-y-integer-width-integer-height-integer-undefined" tabindex="-1"><a class="header-anchor" href="#setviewport-x-integer-y-integer-width-integer-height-integer-undefined" aria-hidden="true">#</a> .setViewport ( x : Integer, y : Integer, width : Integer, height : Integer ) : undefined</h3><p>将视口大小设置为(x, y)到 (x + width, y + height).</p>`,135),d=[i];function l(o,s){return a(),r("div",null,d)}const u=e(n,[["render",l],["__file","WebGLRenderer.html.vue"]]);export{u as default};
